{"root_cause": "description précise", "cause_category": "latency|error_rate|throughput|config|infra_partagee|unknown", "affected_layer": "backend|database|network|k6_config|infra", "fix_action": "description de la correction", "fix_priority": "immediate|high|medium|low", "related_scenarios": []}
